export default function Button({ children, onClick, type = 'button', className = '', variant = 'primary', ...props }) {
  const baseStyle = "px-8 py-4 font-bold rounded-lg transition-all duration-300 font-cairo shadow-md focus:outline-none focus:ring-2 focus:ring-brand-blue-light focus:ring-offset-2";
  
  const variants = {
    primary: "bg-gradient-to-r from-brand-blue to-brand-blue-light text-white shadow-[0_0_20px_rgba(0,86,179,0.4)] hover:shadow-[0_0_30px_rgba(0,170,255,0.6)] hover:-translate-y-1",
    outline: "bg-transparent border-2 border-gray-600 text-white hover:border-gray-300 hover:bg-white/5 backdrop-blur-sm",
  };

  return (
    <button type={type} onClick={onClick} className={`${baseStyle} ${variants[variant]} ${className}`} {...props}>
      {children}
    </button>
  );
}